type UseUpdateLeadProps = {
  onError?: (error: ApiClientError) => void;
  onSuccess?: (data: LeadSubmissionResponse) => void;
};

export const useUpdateLeadPage = ({
  onError,
  onSuccess,
}: UseUpdateLeadProps = {}) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (leadSubmissionRequest: LeadSubmissionRequest) => {
      return getApiClient(false, "public").put<LeadSubmissionResponse>(
        "/submissions/lead",
        leadSubmissionRequest,
      );
    },
    onError: (error: ApiClientError) => {
      onError?.(error);
